// YOUR_AWS_SECRET_KEY_HERE==
// 📅 LOCAL DATE/TIME INITIALIZATION
// YOUR_AWS_SECRET_KEY_HERE==

const now = new Date();

// YOUR_AWS_SECRET_KEY_HERE==
// 🌍 USER-DEFINED TIMEZONE CONFIGURATION
// YOUR_AWS_SECRET_KEY_HERE==
// ⚠️  IMPORTANT: This code runs on the n8n SERVER, not in your browser!
// ⚠️  Configure the timezone where you want executions to be scheduled,
//      regardless of where your n8n server is physically located.
//
// 📍 Common timezone examples:
// - 'Europe/Paris'       → Central European Time (CET/CEST)
// - 'America/New_York'   → Eastern Time (EST/EDT)
// - 'America/Chicago'    → Central Time (CST/CDT)
// - 'America/Los_Angeles'→ Pacific Time (PST/PDT)
// - 'Asia/Tokyo'         → Japan Standard Time (JST)
// - 'Asia/Shanghai'      → China Standard Time (CST)
// - 'Australia/Sydney'   → Australian Eastern Time (AET)
// - 'UTC'                → Coordinated Universal Time
//
// 🔧 TO CONFIGURE FOR YOUR USE CASE:
// 1. Uncomment and edit the lines below with your desired timezone
// 2. Comment out the automatic detection line
//
// To use user-defined timezone instead, UNCOMMENT these lines:
// const USER_TIMEZONE = 'Europe/Paris';  // 👈 EDIT THIS for your location
// const LOCAL_TIMEZONE = USER_TIMEZONE;  // 👈 EDIT THIS for your location
//
// 🕘 Automatic detection (uses server timezone or environment variable):
const LOCAL_TIMEZONE = $env.GENERIC_TIMEZONE || 'Europe/Paris';  // 🟢 Default fallback
// To use user-defined timezone instead, comment out the above line

// Local datetime in YYYY-MM-DD_HH-MM-SS format
const localDateTime = now.toLocaleString('sv-SE', { 
  timeZone: LOCAL_TIMEZONE,
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
  hour: '2-digit',
  minute: '2-digit',
  second: '2-digit'
}).replace(' ', '_').replace(/:/g, '-');

// Local formatted time for display
const localDateTimeFormatted = now.toLocaleString('sv-SE', { 
  timeZone: LOCAL_TIMEZONE,
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
  hour: '2-digit',
  minute: '2-digit',
  second: '2-digit'
});

// Local time HH:MM:SS format
const localTimeFormatted = now.toLocaleString('sv-SE', { 
  timeZone: LOCAL_TIMEZONE,
  hour: '2-digit',
  minute: '2-digit',
  second: '2-digit'
});

// Local date in YYYY-MM-DD format
const localDate = now.toLocaleDateString('sv-SE', { timeZone: LOCAL_TIMEZONE });

// Local time in French format
const localTimeFR = now.toLocaleString('sv-SE', { 
  timeZone: LOCAL_TIMEZONE,
  hour: '2-digit',
  minute: '2-digit'
}).replace(/:/g, 'h').replace(/^0(\d)h/, '$1h');

console.log('🚀 USER-DEFINE TIMEZONE VARIABLES INITIALISED (Local timezone):');
console.log(`   🌍 Timezone: ${LOCAL_TIMEZONE}`);
console.log(`   ✨ Now (UTC): ${now}`);
console.log(`   📅 Local date/time: ${localDateTime}`);
console.log(`   🕐 Local time: ${localDateTimeFormatted}`);
console.log(`   🕐 Local time: ${localTimeFormatted}`);
console.log(`   📅 Local date: ${localDate}`);
console.log(`   📅 Local time (FR): ${localTimeFR}`);

// Create structure for time data output
const timeData = {
  localTimeZone:LOCAL_TIMEZONE,
  nowDateUTC: now,
  nowUTCstring: now.toISOString(),        // UTC for calculations
  localDateTime: localDateTime,     // YYY-MM-DD_HH-MM-SS format
  localDateTimeFormatted: localDateTimeFormatted, // Human readable
  localTimeFormatted: localTimeFormatted, // Human readable
  localDate: localDate,             // YYYY-MM-DD format
  localTime: localTimeFR            // HHhMM format (FR)
}

// YOUR_AWS_SECRET_KEY_HERE==
// 📝 WORKFLOW STANDARD CONFIGURATION
// YOUR_AWS_SECRET_KEY_HERE==

const N8N_ADMIN_EMAIL = $env.N8N_ADMIN_EMAIL || 'user@example.com';
const WORKFLOW_NAME = $workflow.name;
const N8N_PROJECTS_DIR = $env.N8N_PROJECTS_DIR || '/files/n8n-projects-data'; // ⚠️ Your projects’ ROOT folder here
// projects-root-folder/
//   └── Your-project-folder-name/
//       ├── logs/
//       ├── reports/
//       ├── ...
//       └── [other project files]
const PROJECT_FOLDER_NAME = "Workflow-backups"; // ⚠️ Your project folder
const PROJECT_ROOT_PATH = `${N8N_PROJECTS_DIR}/${PROJECT_FOLDER_NAME}`;
// const N8N_MEDIA_ROOT_PATH = $env.N8N_MEDIA_SHARED || '/files/n8n-media-shared'; // ⚠️ Your public folder, accessible from inet
// const mediaOutputFolder = "/output";
// const mediaTempFolder = "/temp";
// const N8N_FILE_SERVER_PURL = $env.N8N_FILE_SERVER_PURL || 'https://files.srv815447.hstgr.cloud'; // File serve public url

const LOGS_PATH = `${PROJECT_ROOT_PATH}/logs`;
// const logFileName = `${localDateTime2}-${WORKFLOW_NAME.replace(/[^a-zA-Z0-9]/g, '_')}_logs.json`;  // ⚠️ Your log file name
const logFileName = `${localDateTime}-backup_logs.json`;  // ⚠️ Your log file name
const logPathFileName = `${LOGS_PATH}/${logFileName}`;

// Configuration for report generation
const REPORTS_PATH = `${PROJECT_ROOT_PATH}/reports`;
const reportFileName = `${localDateTime}-report.txt`;
const reportPathFileName = `${REPORTS_PATH}/${reportFileName}`;

// Console output
console.log('🧾 STANDARD WORKFLOW VARIABLES INITIALISED:');
console.log(`   📁 Admin email: ${N8N_ADMIN_EMAIL}`);
console.log(`   📁 Workflow name: ${WORKFLOW_NAME}`);
console.log(`   📁 Projects folder: ${N8N_PROJECTS_DIR}`);
console.log(`   📁 Project folder name: ${PROJECT_FOLDER_NAME}`);
console.log(`   📁 Project root path: ${PROJECT_ROOT_PATH}`);
// console.log(`   📁 Media root path: ${N8N_MEDIA_ROOT_PATH}`);
// console.log(`   📁 File server public URL: ${N8N_FILE_SERVER_PURL}`);
console.log(`   📁 Log path: ${LOGS_PATH}`);
console.log(`   📁 Log file name: ${logFileName}`);
console.log(`   📁 Log file path: ${logPathFileName}`);
console.log(`   📁 Reports path: ${REPORTS_PATH}`);
console.log(`   📁 Report file name: ${reportFileName}`);
console.log(`   📁 Report file path: ${reportPathFileName}`);

// Create structure for workflow configuration output
const workflowConfig = {
  workflowStep: 'init',
  N8N_ADMIN_EMAIL,
  WORKFLOW_NAME,
  N8N_PROJECTS_DIR,
  PROJECT_FOLDER_NAME,
  PROJECT_ROOT_PATH,
  // N8N_MEDIA_ROOT_PATH,
  // mediaOutputFolder,
  // mediaTempFolder,
  // N8N_FILE_SERVER_PURL,
  LOGS_PATH,
  logFileName,
  logPathFileName,
  REPORTS_PATH,
  reportFileName,
  reportPathFileName
}

// YOUR_AWS_SECRET_KEY_HERE==
// 📝 WORKFLOW CUSTOM CONFIGURATION
// YOUR_AWS_SECRET_KEY_HERE==
// ⚠️  INSERT HERE: your workflow custom configuration variables

// Base backup path using your FTP volume configuration (folder must exist)
const BACKUP_FOLDER = $env.N8N_BACKUP_FOLDER || '/files/n8n-backups'; // ⚠️ Change the default value for your n8n backup folder
const credentials_temp_folder = '-restore-credentials';
const workflows_temp_folder = '-restore-workflows';
const FTP_BACKUP_FOLDER = $env.FTP_BACKUP_FOLDER || '/n8n-backups';
const FTPName = 'Your FTP Server Name';

const credentials = "n8n-credentials";

// Console output
console.log('🧾 CUSTOM WORKFLOW VARIABLES INITIALISED:');
console.log(`   💾 Backup folder: ${BACKUP_FOLDER}`);
console.log('      File prefix:', localDate);
console.log('      Timestamp (UTC):', now);

const customConfig = {
  backupFolder: BACKUP_FOLDER,
  credentials_temp_folder,
  workflows_temp_folder,
  FTP_BACKUP_FOLDER,
  FTPName,
  credentials
}

// YOUR_AWS_SECRET_KEY_HERE==
// 📊 OUTPUT DATA
// YOUR_AWS_SECRET_KEY_HERE==

const initData = {
  timeData,
  workflowConfig,
  customConfig
};

return [{ json: initData }];

// YOUR_AWS_SECRET_KEY_HERE==
// 🔍 FIND LATEST BACKUP FOLDER FROM FTP
// YOUR_AWS_SECRET_KEY_HERE==
// ⚠️ CONFIGURE THIS NODE WITH:
// SETTINGS > ON ERROR > CONTINUE (USING ERROR OUTPUT)

// Extract init data from Init node
const initData = $('Init').first().json;
const { customConfig } = initData;

const FTP_BACKUP_FOLDER = customConfig.FTP_BACKUP_FOLDER;
const credentials = customConfig.credentials;

console.log(`🔍 Searching for latest backup in FTP: ${FTP_BACKUP_FOLDER}`);
console.log(`📁 Target credentials folder: ${credentials}`);

try {
  // Get FTP listing from previous node (List FTP)
  const ftpListing = $input.all();

  if (!ftpListing || ftpListing.length === 0) {
    throw new Error('No FTP listing found. Please check FTP connection.');
  }

  console.log(`📂 FTP returned ${ftpListing.length} item(s)`);

  // Filter for directories only (type 'd') with date format YYYY-MM-DD
  const datePattern = /^\d{4}-\d{2}-\d{2}$/;
  const dateDirectories = ftpListing
    .filter(item => {
      const itemData = item.json;
      // FTP node returns items with 'name' and 'type' properties
      // type 'd' = directory, type '-' = file
      const isDirectory = itemData.type === 'd' || itemData.type === 1; // type can be string or number
      const matchesDateFormat = datePattern.test(itemData.name);

      if (isDirectory && matchesDateFormat) {
        console.log(`✓ Found date directory: ${itemData.name}`);
      }

      return isDirectory && matchesDateFormat;
    })
    .map(item => item.json.name);

  console.log(`📅 Found ${dateDirectories.length} date-formatted directories`);

  if (dateDirectories.length === 0) {
    throw new Error('No date-formatted directories (YYYY-MM-DD) found in FTP backup folder');
  }

  // Sort directories by date (newest first)
  const sortedDirectories = dateDirectories.sort((a, b) => {
    const dateA = new Date(a);
    const dateB = new Date(b);
    return dateB - dateA; // Descending order (newest first)
  });

  console.log(`📅 Sorted directories (newest first): ${sortedDirectories.join(', ')}`);

  // Get the most recent directory
  const latestBackupDate = sortedDirectories[0];
  const ftpCredentialsPath = `${FTP_BACKUP_FOLDER}/${latestBackupDate}/${credentials}`;
  const ftpWorkflowsPath = `${FTP_BACKUP_FOLDER}/${latestBackupDate}/`;

  console.log(`✅ Latest backup date: ${latestBackupDate}`);
  console.log(`✅ FTP credentials path: ${ftpCredentialsPath}`);

  // Return result for next node
  const result = {
    latestBackupDate,
    ftpCredentialsPath,
    ftpWorkflowsPath,
    FTP_BACKUP_FOLDER,
    credentialsFolder: credentials
  };

  return [{ json: result }];

} catch (error) {
  console.error(`❌ Error finding latest backup: ${error.message}`);
  throw new Error(`Failed to find latest backup: ${error.message}`);
}
